mapper.select:
SELECT wiki_page_id, project_id, parent_page_id, title, current_version, user_code, created_at, update_at FROM wiki_pages WHERE project_id = #{projectId}
AND title LIKE '%' || #{keyword} || '%'
ORDER BY created_at ASC

SELECT
    wiki_history_id, wiki_page_id, wiki_version,
    title, content, user_code, created_at
FROM wiki_histories
WHERE wiki_page_id = #{wikiPageId}
  AND wiki_version  = #{wikiVersion}

SELECT profile_image
FROM users
WHERE user_code = #{userCode}

mapper.update:
UPDATE wiki_pages
SET lock_user_code = NULL,
    locked_at      = NULL
WHERE wiki_page_id  = #{wikiPageId}
  AND lock_user_code = #{userCode}

mapper.select:
SELECT DISTINCT rp.permission_code
FROM members m
JOIN member_roles mr ON m.member_id = mr.member_id
JOIN role_permissions rp ON mr.role_id = rp.role_id
WHERE m.user_code = #{userCode}
  AND m.project_id = #{projectId}
